/*
 * COMP 321 Project 1: Factors
 *
 * This program computes the number of prime factors, and optionally the number
 * of distinct prime factors, for an unsigned integer input.
 * 
 * <Put your name and NetID here>
 */

#include <assert.h>
#include <math.h>     // Included in case you use the standard math library.
#include <stdbool.h>
#include <stdio.h>
#include <unistd.h>

static unsigned int	count_distinct_factors(unsigned int n);
static unsigned int	count_factors(unsigned int n);
static unsigned int	count_factors_recursive(unsigned int n);
static void		test_factors(void);

// Replace this comment with any global variable declarations.

/*
 * Requires:
 *   n > 1 and divisor >= 2
 *
 * Effects:
 *   Returns the smallest prime factor of n that is >= divisor.
 *   Recursively checks divisors without using loops.
 */
static unsigned int
find_smallest_factor(unsigned int n, unsigned int divisor)
{
	if (divisor * divisor > n) {
		return n;  // n is prime
	}
	if (n % divisor == 0) {
		return divisor;  // Found smallest factor
	}
	return find_smallest_factor(n, divisor + 1);
}

/*
 * Requires:
 *   The input "n" must be greater than 1.
 *
 * Effects:
 *   Returns the number of factors of the input "n".
 */
static unsigned int
count_factors_recursive(unsigned int n)
{
	unsigned int factor;

	if (n == 1) {
		return (0);
	}

	assert(n > 1);

	factor = find_smallest_factor(n, 2);
	return (1 + count_factors_recursive(n / factor));
}

/*
 * Requires:
 *   The input "n" must be greater than 1.
 *
 * Effects:
 *   Returns the number of factors of the input "n".
 */
static unsigned int
count_factors(unsigned int n)
{
	unsigned int count = 0;
	unsigned int divisor = 2;

	assert(n > 1);

	while (divisor * divisor <= n) {
		while (n % divisor == 0) {
			count++;
			n /= divisor;
		}
		divisor++;
	}

	if (n > 1) {
		count++;
	}

	return (count);
}

/*
 * Requires:
 *   The input "n" must be greater than 1.
 *
 * Effects:
 *   Returns the number of distinct factors of the input "n".
 */
static unsigned int
count_distinct_factors(unsigned int n)
{
	unsigned int count = 0;
	unsigned int divisor = 2;

	assert(n > 1);

	while (divisor * divisor <= n) {
		if (n % divisor == 0) {
			count++;
			while (n % divisor == 0) {
				n /= divisor;
			}
		}
		divisor++;
	}

	if (n > 1) {
		count++;
	}

	return (count);
}

/*
 * Requires:
 *   Nothing.
 *
 * Effects:
 *   Runs testing procedures.
 */
static void
test_factors(void)
{
	printf("Testing count_factors:\n");

	assert(count_factors(2) == 1);       // 2
	assert(count_factors(3) == 1);       // 3
	assert(count_factors(4) == 2);       // 2 * 2
	assert(count_factors(12) == 3);      // 2 * 2 * 3
	assert(count_factors(13) == 1);      // 13 (prime)
	assert(count_factors(30) == 3);      // 2 * 3 * 5
	assert(count_factors(100) == 4);     // 2 * 2 * 5 * 5

	printf("Testing count_distinct_factors:\n");

	assert(count_distinct_factors(2) == 1);    // 2
	assert(count_distinct_factors(3) == 1);    // 3
	assert(count_distinct_factors(4) == 1);    // 2 * 2
	assert(count_distinct_factors(12) == 2);   // 2 * 3
	assert(count_distinct_factors(13) == 1);   // 13 (prime)
	assert(count_distinct_factors(30) == 3);   // 2 * 3 * 5
	assert(count_distinct_factors(100) == 2);  // 2 * 5

	printf("Testing count_factors_recursive:\n");

	assert(count_factors_recursive(2) == 1);   // 2
	assert(count_factors_recursive(3) == 1);   // 3
	assert(count_factors_recursive(4) == 2);   // 2 * 2
	assert(count_factors_recursive(12) == 3);  // 2 * 2 * 3
	assert(count_factors_recursive(13) == 1);  // 13 (prime)
	assert(count_factors_recursive(30) == 3);  // 2 * 3 * 5
	assert(count_factors_recursive(100) == 4); // 2 * 2 * 5 * 5

	printf("All tests passed!\n");
}

/* 
 * Requires:
 *   Nothing.
 *
 * Effects:
 *   If the "-t" option is specified on the command line, then test code is
 *   executed and the program exits.
 *   
 *   Otherwise, requests a number from standard input.  If the "-r" option is
 *   specified on the command line, then prints the number of prime factors
 *   that the input number has, calculated using a recursive function.
 *   Otherwise, prints the number of prime factors that the input number has
 *   and the number of those factors that are distinct using iterative
 *   functions.
 *
 *   Upon completion, the program always returns 0.
 *
 *   If the number that is input is not between 2 and the largest unsigned
 *   integer, the output of the program is undefined, but it will not crash.
 */
int
main(int argc, char **argv)
{
	unsigned int n;
	int c;
	bool recursive = false;
	bool runtests = false;

	// Parse the command line.
	while ((c = getopt(argc, argv, "rt")) != -1) {
		switch (c) {
		case 'r':             // Use recursive version.
			recursive = true;
			break;
		case 't':             // Run test procedure and exit.
			runtests = true;
			break;
		default:
			break;
		}
	}

	// If "-t" is specified, run test procedure and exit program.
	if (runtests) {
		test_factors();
		return (0);
	}

	// Get input.
	printf("Enter number:\n");
	if (scanf("%u", &n) != 1) {
		fprintf(stderr, "Input error\n");
		return (1);
	}

	// Validate the input.
	if (n < 2) {
		fprintf(stderr, "Invalid input: %u\n", n);
		return (1);
	}

	// Print results.
	if (recursive) {
		// Use recursive version.
		printf("%u has %u prime factors.\n",
		    n, count_factors_recursive(n));
	} else {
		// Use iterative versions.
		printf("%u has %u prime factors, %u of them distinct.\n",
		    n, count_factors(n), count_distinct_factors(n));
	}

	// Report no errors.
	return (0);
}

